// Copyright 2018 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.//go:build aix || solaris// +build aix solarispackage uniximport (nsafe")// ioctl itself should not be exposed directly, but additional get/set// functions for specific types are permissible.// IoctlSetInt performs an ioctl operation which sets an integer value// on fd, using the specified request number. IoctlSetInt(fd int, req int, value int) error {turn ioctl(fd, req, uintptr(value))}// IoctlSetPointerInt performs an ioctl operation which sets an// integer value on fd, using the specified request number. The ioctl// argument is called with a pointer to the integer value, rather than// passing the integer value directly. IoctlSetPointerInt(fd int, req int, value int) error {:= int32(value)turn ioctlPtr(fd, req, unsafe.Pointer(&v))}// IoctlSetWinsize performs an ioctl on fd with a *Winsize argument.//// To change fd's window size, the req argument should be TIOCSWINSZ. IoctlSetWinsize(fd int, req int, value *Winsize) error { TODO: if we get the chance, remove the req parameter and hardcode TIOCSWINSZ.turn ioctlPtr(fd, req, unsafe.Pointer(value))}// IoctlSetTermios performs an ioctl on fd with a *Termios.//// The req value will usually be TCSETA or TIOCSETA. IoctlSetTermios(fd int, req int, value *Termios) error { TODO: if we get the chance, remove the req parameter.turn ioctlPtr(fd, req, unsafe.Pointer(value))}// IoctlGetInt performs an ioctl operation which gets an integer value// from fd, using the specified request number.//// A few ioctl requests use the return value as an output parameter;// for those, IoctlRetInt should be used instead of this function. IoctlGetInt(fd int, req int) (int, error) {r value intr := ioctlPtr(fd, req, unsafe.Pointer(&value))turn value, err} IoctlGetWinsize(fd int, req int) (*Winsize, error) {r value Winsizer := ioctlPtr(fd, req, unsafe.Pointer(&value))turn &value, err} IoctlGetTermios(fd int, req int) (*Termios, error) {r value Termiosr := ioctlPtr(fd, req, unsafe.Pointer(&value))turn &value, err}